  "🏥": "hospital",
  "🩺": "stethoscope",
  "🫁": "wind",
  "🔥": "flame",
  "⏱️": "timer",
  "⚡": "zap",
  "⭐": "star",
  "✓": "check",
  "❌": "x",
  "⚠️": "alert-triangle",
  "🧠": "brain",
  "💓": "heart-pulse",
